  ('police-3fd24912-moex-00169', 'police-3fd24912', 'police-3fd24912-moex-112-15a7b19c', 'sub-police-3fd24912-01', NULL, 'single_choice', '依司法院大法官解釋，下列何者不構成對居住遷徙自由之限制？', '["為維護水庫用水之潔淨與安全，要求原居水質保護區之居民集體遷村", "為避免役男出國逃避兵役，立法要求役男出國前須向主管機關核備", "法律規定在特定要件下，主管機關得不待大陸地區人民申辯，強制逕予出境", "我國政府與他國斷交，致該國拒絕核發簽證予我國國民"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:59+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "504", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "公共安全人員"}'::jsonb, NULL),
  ('police-3fd24912-moex-00170', 'police-3fd24912', 'police-3fd24912-moex-112-15a7b19c', 'sub-police-3fd24912-01', NULL, 'single_choice', '依司法院大法官解釋及現行制度，關於憲法第16條保障之訴訟權，下列敘述何者錯誤？', '["法官迴避制度屬訴訟權保障之核心內容", "基於訴訟權保障及法官依法獨立審判，法定法官原則為我國應遵循之憲法原則", "公務人員對於服務機關所為之行政處分及管理措施，認違法損害其權利或利益者，均得提 起行政訴訟", "訴訟救濟應循普通訴訟或依行政訴訟為之，由立法機關衡量訴訟案件之性質及訴訟制度之 功能等因素定之"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:59+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "504", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "police", "civil_category": "公共安全人員"}'::jsonb, NULL),
