  ('police-3fd24912-moex-00172', 'police-3fd24912', 'police-3fd24912-moex-112-15a7b19c', 'sub-police-3fd24912-01', NULL, 'single_choice', '依憲法規定及司法院大法官解釋，關於立法權與行政權之關係，下列敘述何者錯誤？', '["行政院有向立法院提出施政方針及施政報告之責", "立法委員在開會時有向行政院院長及各部會首長質詢之權", "立法院於每年集會時，得聽取總統國情報告", "立法院不得對任何獨立行使職權之機關行使調查權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:59+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "504", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "公共安全人員"}'::jsonb, NULL),
  ('police-3fd24912-moex-00173', 'police-3fd24912', 'police-3fd24912-moex-112-15a7b19c', 'sub-police-3fd24912-01', NULL, 'single_choice', '依現行憲法增修條文及司法院大法官解釋，關於監察院及監察委員之敘述，下列何者錯誤？', '["監察委員有固定任期", "監察委員經立法院同意任命之", "監察委員依據法律獨立行使職權", "監察院屬於中央民意代表機構"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:59+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "504", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "公共安全人員"}'::jsonb, NULL),
  ('police-3fd24912-moex-00174', 'police-3fd24912', 'police-3fd24912-moex-112-15a7b19c', 'sub-police-3fd24912-01', NULL, 'single_choice', '依憲法及司法院大法官解釋，關於公務員懲戒，下列敘述何者錯誤？', '["公務員懲戒屬司法權之一環", "懲戒法院為行使懲戒權之專屬機關", "懲戒法院之審議，應予以付懲戒人充分程序保障，包括採取直接審理及給予最後陳述之機會", "公務員懲戒法未設有通常上訴救濟之機制，屬於立法形成自由，未對人民訴訟權構成侵害"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:59+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "504", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 28, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "police", "civil_category": "公共安全人員"}'::jsonb, NULL),
  ('police-3fd24912-moex-00175', 'police-3fd24912', 'police-3fd24912-moex-112-15a7b19c', 'sub-police-3fd24912-01', NULL, 'single_choice', '依憲法增修條文第10條第7項及第9項之規定，國家對於身心障礙者及退役軍人，應提供 特別之保障及照顧。依司法院大法官解釋意旨，下列敘述何者正確？', '["立法者制定相關法律給予身心障礙者及退役軍人特別保障，其立法目的合憲", "政府採購法規定得標廠商應強制聘僱一定比例之身心障礙者及原住民，未及於退役軍人， 違反上述增修條文規定", "基於上述增修條文規定，退役軍人得請求國家應於國立大學之招生簡章中規定退役軍人錄 取之保障名額", "法律為保障視障者之工作權，排除其他身心障礙者及非視障者從事按摩業之就業機會，符 合平等保障"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:59+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "504", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "公共安全人員"}'::jsonb, NULL),
