  ('police-3fd24912-moex-00177', 'police-3fd24912', 'police-3fd24912-moex-112-15a7b19c', 'sub-police-3fd24912-01', NULL, 'single_choice', '依司法院大法官解釋，有關應考試服公職權，下列敘述何者錯誤？', '["國家須設置客觀公平之考試制度，係為實踐憲法保障人民應考試服公職權利之意旨", "就人民應考試服公職權所為之差別待遇，司法應採較為嚴格之審查基準", "以警大容訓量有限為由，排除一般生於警大完成訓練之機會，係屬重要公益", "將一般生一律安排至警專受訓之手段，與擇優選才目的之達成間難謂具實質關聯"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:59+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "504", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "公共安全人員"}'::jsonb, NULL),
